"""
An implementation of JSON Schema for Python.

The main functionality is provided by the validator classes for each of the
supported JSON Schema versions.

Most commonly, `jsonschema.validators.validate` is the quickest way to simply
validate a given instance under a schema, and will create a validator
for you.
"""
__version__ = "4.26.0"

import warnings

# All public names are resolved lazily via __getattr__ to avoid circular
# imports (jsonschema -> validators -> jsonschema_specifications -> referencing
# -> back to jsonschema before it finishes initialising).

_LAZY_IMPORTS = {
    "FormatChecker": ("jsonschema._format", "FormatChecker"),
    "TypeChecker": ("jsonschema._types", "TypeChecker"),
    "SchemaError": ("jsonschema.exceptions", "SchemaError"),
    "ValidationError": ("jsonschema.exceptions", "ValidationError"),
    "Draft3Validator": ("jsonschema.validators", "Draft3Validator"),
    "Draft4Validator": ("jsonschema.validators", "Draft4Validator"),
    "Draft6Validator": ("jsonschema.validators", "Draft6Validator"),
    "Draft7Validator": ("jsonschema.validators", "Draft7Validator"),
    "Draft201909Validator": ("jsonschema.validators", "Draft201909Validator"),
    "Draft202012Validator": ("jsonschema.validators", "Draft202012Validator"),
    "validate": ("jsonschema.validators", "validate"),
}


def __getattr__(name):
    # Fast path: known lazy imports
    if name in _LAZY_IMPORTS:
        module_path, attr_name = _LAZY_IMPORTS[name]
        import importlib
        mod = importlib.import_module(module_path)
        value = getattr(mod, attr_name)
        # Cache on the module so __getattr__ is not called again
        globals()[name] = value
        return value

    if name == "__version__":
        warnings.warn(
            "Accessing jsonschema.__version__ is deprecated and will be "
            "removed in a future release. Use importlib.metadata directly "
            "to query for jsonschema's version.",
            DeprecationWarning,
            stacklevel=2,
        )

        from importlib import metadata
        return metadata.version("jsonschema")
    elif name == "RefResolver":
        from jsonschema.validators import _RefResolver
        warnings.warn(
            _RefResolver._DEPRECATION_MESSAGE,
            DeprecationWarning,
            stacklevel=2,
        )
        return _RefResolver
    elif name == "ErrorTree":
        warnings.warn(
            "Importing ErrorTree directly from the jsonschema package "
            "is deprecated and will become an ImportError. Import it from "
            "jsonschema.exceptions instead.",
            DeprecationWarning,
            stacklevel=2,
        )
        from jsonschema.exceptions import ErrorTree
        return ErrorTree
    elif name == "FormatError":
        warnings.warn(
            "Importing FormatError directly from the jsonschema package "
            "is deprecated and will become an ImportError. Import it from "
            "jsonschema.exceptions instead.",
            DeprecationWarning,
            stacklevel=2,
        )
        from jsonschema.exceptions import FormatError
        return FormatError
    elif name == "Validator":
        warnings.warn(
            "Importing Validator directly from the jsonschema package "
            "is deprecated and will become an ImportError. Import it from "
            "jsonschema.protocols instead.",
            DeprecationWarning,
            stacklevel=2,
        )
        from jsonschema.protocols import Validator
        return Validator
    elif name == "RefResolutionError":
        from jsonschema.exceptions import _RefResolutionError
        warnings.warn(
            _RefResolutionError._DEPRECATION_MESSAGE,
            DeprecationWarning,
            stacklevel=2,
        )
        return _RefResolutionError

    # Deprecated format checker accessors — also lazy to avoid circular imports
    _format_checker_map = {
        "draft3_format_checker": "Draft3Validator",
        "draft4_format_checker": "Draft4Validator",
        "draft6_format_checker": "Draft6Validator",
        "draft7_format_checker": "Draft7Validator",
        "draft201909_format_checker": "Draft201909Validator",
        "draft202012_format_checker": "Draft202012Validator",
    }
    if name in _format_checker_map:
        validator_name = _format_checker_map[name]
        warnings.warn(
            f"Accessing jsonschema.{name} is deprecated and will be "
            "removed in a future release. Instead, use the FORMAT_CHECKER "
            "attribute on the corresponding Validator.",
            DeprecationWarning,
            stacklevel=2,
        )
        import importlib
        mod = importlib.import_module("jsonschema.validators")
        validator_cls = getattr(mod, validator_name)
        return validator_cls.FORMAT_CHECKER

    raise AttributeError(f"module {__name__} has no attribute {name}")


__all__ = [
    "Draft3Validator",
    "Draft4Validator",
    "Draft6Validator",
    "Draft7Validator",
    "Draft201909Validator",
    "Draft202012Validator",
    "FormatChecker",
    "SchemaError",
    "TypeChecker",
    "ValidationError",
    "validate",
]
